import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import response from './response.json';

interface CartSummary {
  itemCount: number;
  totalPrice: number;
  totalSavings: number;
}

interface Item {
  name: string;
  price: number;
  savings: number;
}

interface CartData {
  cartSummary: CartSummary;
  items: Item[];
}

export default function Widget() {
  const cartData = response.data as CartData;
  const { cartSummary, items } = cartData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 300, maxWidth: 400, bgcolor: '#FFFFFF', borderRadius: 2 }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FF5722' }}>
              Cart Summary
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Items: {cartSummary.itemCount}
            </Typography>
            <Typography variant="h5" sx={{ color: '#FF5722', mt: 0.5 }}>
              Total: ${cartSummary.totalPrice.toFixed(2)}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Savings: ${cartSummary.totalSavings.toFixed(2)}
            </Typography>
          </Box>

          <Divider />

          <Stack spacing={1}>
            {items.map((item, index) => (
              <Box key={index}>
                <Typography variant="body2" fontWeight={600} color="text.primary">
                  {item.name}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  Price: ${item.price.toFixed(2)} | Savings: ${item.savings.toFixed(2)}
                </Typography>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
